#include <bits/stdc++.h>
using namespace std;

const int N=2e6+10;

int n,p[N],f[N],lst[N][26];
long long ans;
char s[N];

int main(){
    scanf("%d",&n);
    scanf("%s",s+1);
    p[1]=-1;
    lst[1][s[1]-'a']=1;
    for(int i=2;i<=n;i++){
        p[i]=lst[i-1][s[i]-'a']-1;
        if(~p[i])
            for(int j=0;j<26;j++)
                lst[i][j]=lst[p[i]][j];
        lst[i][s[i]-'a']=i;
        if(~p[i]) f[i]=f[p[i]]+1;
        ans+=f[i];
    }
    printf("%lld",ans);
    return 0;
}
